void main() {
  var defaultConfig = {
    'theme': 'light',
    'language': 'en',
    'notifications': true,
  };

  var userConfig = {
    'theme': 'dark',
    'fontSize': 14,
  };

  // Merge with user preferences overriding defaults
  var finalConfig = {...defaultConfig, ...userConfig};
  print(finalConfig);

  // Combining lists with spread
  var evens = [2, 4, 6];
  var odds = [1, 3, 5];
  var allNumbers = [...odds, ...evens]..sort();
  print(allNumbers);

  // Null-safe spread
  List<String>? extraNames;
  var names = ['Alice', ...?extraNames, 'Bob'];
  print(names);
}
